  ('locality-e0adf6cd-moex-00041', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-114-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '關於政府資訊限制公開或不予公開事由之敘述，下列何者錯誤？', '["政府機關為實施取締業務，而取得取締對象之相關資料，其公開將對實施目的造成困難者，應 限制或不予公開，並無例外", "公營事業機構經營之有關資料，其公開將妨害其經營上之正當利益者，應限制或不予公開，並 無例外", "政府機關作成意思決定前，內部單位之擬稿或其他準備作業，如對公益有必要者，仍得公開", "資訊之公開有侵害個人隱私，如對公益有必要者，仍得公開"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "308", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00042', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-114-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '經濟部智慧財產局訂頒商標識別性審查基準，如甲文創公司認經營環境受到限制，不服該審查基 準，關於其救濟，下列敘述何者正確？', '["甲得逕向憲法法庭聲請宣告該審查基準為違憲", "甲得逕向高等行政法院起訴請求撤銷該審查基準", "甲得請求行政法院聲請憲法法庭宣告該審查基準違憲", "需由經濟部智慧財產局依該審查基準對甲作成處分後，甲始得對該處分提起訴願、行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "308", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00043', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-114-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '關於訴願期間行政處分停止執行之敘述，下列何者錯誤？', '["訴願人於訴願程序終結前，亦得向行政法院聲請停止執行", "原行政處分之執行，原則上不因提起訴願而停止", "訴願人僅得就原行政處分之全部聲請停止執行，以維護行政權之完整性", "受理訴願機關認為原行政處分之合法性顯有疑義，得依職權命原處分機關停止執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "308", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00044', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-114-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '甲為公益團體，認為A工廠長年違法傾倒廢棄物，致使周遭農地受到污染，遂依廢棄物清理法規 定，以書面向當地主管機關乙請求依法行使公權力。若乙未在法定期間內採取任何作為，而甲欲 依行政訴訟法規定提起公益訴訟時，下列敘述何者正確？', '["本案仍應視其具體主張而提起特定訴訟類型", "甲必須證明自身權益亦遭受損害，始得提起本案訴訟", "向行政法院提起訴訟前，一律須經訴願程序", "此種訴訟屬於備位性質，必須限於無法提起其他行政訴訟時，始得提起"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "308", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00045', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-114-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '關於行政訴訟制度之敘述，下列何者正確？', '["提起一般給付訴訟應經訴願先行程序", "提起都市計畫審查程序應向都市計畫區所在地之高等行政法院為之", "公職人員選舉罷免法明定之選舉訴訟係向行政法院提起", "不服律師懲戒委員會作成之懲戒處分係向行政法院提起訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "308", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00046', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-114-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '關於賠償義務機關，下列敘述何者正確？', '["公共設施委託民間團體管理時，因管理欠缺致人民生命受有損害者，以該民間團體為賠償義務 機關", "受託行使公權力之團體，其執行職務之人於行使公權力時所生之國家賠償責任，以該團體為賠 償義務機關", "賠償義務機關經裁撤或改組者，原則上應優先以其裁撤或改組前之上級機關為賠償義務機關", "無法確定賠償義務機關而請求上級機關確定，上級機關逾期不為確定者，得逕以該上級機關為 賠償義務機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "308", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00047', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-114-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '下列何種情形，國家應負損害賠償責任？', '["各級政府機關依中央流行疫情指揮中心指揮官之指示，徵用私立醫療機構設立檢疫場所", "既成道路或都市計畫道路用地，在依法徵收或價購前所埋設之地下設施，致妨礙土地權利人對 其權利之行使", "私人建築物被指定為古蹟，致所有權人無法為使用收益", "土地因地政機關登記遺漏，致人民無法主張權利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "48d6624b1660", "answer_pdf_sha1": "655232f0d966", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "308", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00048', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-856e6567', 'sub-locality-e0adf6cd-01', NULL, 'essay', '實踐智慧（phronesis,practicalwisdom）是教育行政人員或教師需要具備
的重要素養，而亞里斯多德（Aristotle）區分實踐智慧和科學知識
（episteme,scientificknowledge）及技藝（techne,art）這三種理智德行。
在培育教育行政人員或教師的規劃上，相對應的有下列三種模式：科學
知識的應用模式、技藝製造的生產模式及德行為本的素養模式。請說明
這三種理智德行的意義？這三種培育模式的重點是什麼？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "9d403f46313a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "1008", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育哲學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00049', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-856e6567', 'sub-locality-e0adf6cd-01', NULL, 'essay', '當代教育思想家比斯塔（G. Biesta）論及教育目的或教育的功能時，共
